arguments.content:
[package]
name = "spirit-luna-witness"
version = "0.0.0"
edition = "2024"
publish = false

[dependencies]
spirit-judge = { path = "/home/li/primary/repos/spirit-judge" }
signal-spirit-judge = { git = "https://github.com/LiGoldragon/signal-spirit-judge.git", rev = "7c25b71a34858c0d912dff8fd0b4f4ac213d7cd1" }
signal-spirit = { git = "https://github.com/LiGoldragon/signal-spirit.git", rev = "1cf7c010029de46369b742687da4fa1ca6def9a9", default-features = false }
tokio = { version = "1", features = ["rt-multi-thread", "macros"] }

use spirit_judge::{SpiritJudgeClient, SpiritJudgeSocketPath};
use signal_spirit::schema::signal::{
    Certainty, CommitSequence, DatabaseMarker, Description, Domains, Entry, Importance,
    Justification, Kind, Magnitude, Privacy, Reasoning, RecordRequest, RecordSet, Referents,
    StateDigest, Testimony,
};
use signal_spirit_judge::{
    AdmissionJudgeOperation, AdmissionJudgePacket, JudgmentScope, SpiritJudgeReply,
    SpiritJudgeRequest,
};

#[tokio::main]
async fn main() {
    let socket = std::env::args().nth(1).expect("socket path is required");
    let request = SpiritJudgeRequest::JudgeAdmission(AdmissionJudgePacket::new(
        JudgmentScope::public(),
        AdmissionJudgeOperation::Record(RecordRequest {
            entry: Entry {
                domains: Domains::new(Vec::new()),
                kind: Kind::Principle,
                description: Description::new("Provider compatibility witness."),
                certainty: Certainty::new(Magnitude::High),
                importance: Importance::new(Magnitude::Medium),
                privacy: Privacy::new(Magnitude::Zero),
                referents: Referents::new(Vec::new()),
            },
            justification: Justification {
                testimony: Testimony::new(Vec::new()),
                reasoning: Reasoning::new("isolated provider witness"),
            },
        }),
        RecordSet::new(Vec::new()),
        DatabaseMarker {
            commit_sequence: CommitSequence::new(0),
            state_digest: StateDigest::new(0),
        },
    ));
    let reply = SpiritJudgeClient::new(SpiritJudgeSocketPath::new(socket))
        .submit(request)
        .await
        .expect("judge socket exchange");
    let class = match reply {
        SpiritJudgeReply::AdmissionJudged(_) => "admission-judged",
        SpiritJudgeReply::ReferentRegistrationJudged(_) => "referent-registration-judged",
        SpiritJudgeReply::RequestRejected(_) => "request-rejected",
    };
    println!("{class}");
}
